const tls = require('tls');
const net = require('net');

function createSecureAndCleartextPair({ key, cert, ca, serverName, alpn } = {}) {
  const server = tls.createServer({
    key,
    cert,
    ca,
    serverName,
    ALPNProtocols: alpn,
    requestCert: !!ca,
    rejectUnauthorized: !!ca,
  });

  const clearServer = net.createServer();

  const clearClient = new net.Socket();
  const clearServerConn = new Promise((resolve, reject) => {
    clearServer.once('error', reject);
    clearServer.once('connection', (s) => resolve(s));
  });

  const secureClient = new tls.TLSSocket(clearClient, {
    isServer: false,
    servername: serverName,
    ca,
    rejectUnauthorized: !!ca,
    ALPNProtocols: alpn,
  });

  const secureServerConn = new Promise((resolve, reject) => {
    server.once('error', reject);
    server.once('secureConnection', (s) => resolve(s));
  });

  return (async () => {
    await new Promise((r) => server.listen(0, r));
    await new Promise((r) => clearServer.listen(0, r));

    const securePort = server.address().port;
    const clearPort = clearServer.address().port;

    clearClient.connect(clearPort, '127.0.0.1');
    const [secureServerSocket, clearServerSocket] = await Promise.all([
      secureServerConn,
      clearServerConn,
    ]);

    const secureClientSocket = tls.connect({
      port: securePort,
      host: '127.0.0.1',
      key: undefined,
      cert: undefined,
      ca,
      servername: serverName,
      rejectUnauthorized: !!ca,
      ALPNProtocols: alpn,
    });

    await new Promise((resolve, reject) => {
      secureClientSocket.once('secureConnect', resolve);
      secureClientSocket.once('error', reject);
    });

    return {
      secure: { client: secureClientSocket, server: secureServerSocket },
      clear: { client: clearClient, server: clearServerSocket },
    };
  })();
}
