function evaluateExpression(expr) {
  if (typeof expr !== "string") throw new TypeError("Expression must be a string");
  const s = expr.replace(/\s+/g, "");
  if (!s) throw new Error("Empty expression");

  if (!/^[0-9+\-*/().%]*$/.test(s)) throw new Error("Invalid characters");

  const tokens = s.match(/(\d+(?:\.\d+)?)|[+\-*/()%]/g);
  if (!tokens) throw new Error("Invalid expression");

  const prec = { "+": 1, "-": 1, "*": 2, "/": 2, "%": 2 };
  const assoc = { "+": "L", "-": "L", "*": "L", "/": "L", "%": "L" };

  const output = [];
  const ops = [];

  const isOp = (t) => t in prec;

  for (let i = 0; i < tokens.length; i++) {
    const t = tokens[i];
    if (/^\d/.test(t)) {
      output.push(Number(t));
      continue;
    }
    if (t === "(") {
      ops.push(t);
      continue;
    }
    if (t === ")") {
      while (ops.length && ops[ops.length - 1] !== "(") output.push(ops.pop());
      if (!ops.length) throw new Error("Mismatched parentheses");
      ops.pop();
      continue;
    }
    if (isOp(t)) {
      // Handle unary +/-
      const prev = tokens[i - 1];
      const next = tokens[i + 1];
      const unary = (t === "+" || t === "-") && (i === 0 || prev === "(" || isOp(prev));
      if (unary) {
        if (next == null) throw new Error("Invalid unary operator");
        if (/^\d/.test(next)) {
          output.push(t === "-" ? -Number(next) : Number(next));
          i++;
          continue;
        }
        if (next === "(") {
          // Convert -(...) to 0-(...)
          if (t === "-") output.push(0);
          // For unary +, just ignore
          continue;
        }
        throw new Error("Invalid unary operator usage");
      }

      while (
        ops.length &&
        isOp(ops[ops.length - 1]) &&
        ((assoc[t] === "L" && prec[t] <= prec[ops[ops.length - 1]]) ||
          (assoc[t] === "R" && prec[t] < prec[ops[ops.length - 1]]))
      ) {
        output.push(ops.pop());
      }
      ops.push(t);
      continue;
    }
    throw new Error("Invalid token");
  }

  while (ops.length) {
    const op = ops.pop();
    if (op === "(" || op === ")") throw new Error("Mismatched parentheses");
    output.push(op);
  }

  const stack = [];
  for (const item of output) {
    if (typeof item === "number") {
      stack.push(item);
      continue;
    }
    const b = stack.pop();
    const a = stack.pop();
    if (a == null || b == null) throw new Error("Invalid expression");
    switch (item) {
      case "+": stack.push(a + b); break;
      case "-": stack.push(a - b); break;
      case "*": stack.push(a * b); break;
      case "/": stack.push(a / b); break;
      case "%": stack.push(a % b); break;
      default: throw new Error("Unknown operator");
    }
  }
  if (stack.length !== 1) throw new Error("Invalid expression");
  const result = stack[0];
  if (!Number.isFinite(result)) throw new Error("Result is not finite");
  return result;
}
