const unmountApp = (container) => {
  if (!container) return;
  const root = container._reactRootContainer;
  if (root && typeof ReactDOM.unmountComponentAtNode === "function") {
    ReactDOM.unmountComponentAtNode(container);
    return;
  }
  if (typeof ReactDOM.createRoot === "function") {
    const existing = container.__reactRootContainer;
    if (existing && typeof existing.unmount === "function") existing.unmount();
    else if (typeof ReactDOM.unmountComponentAtNode === "function") ReactDOM.unmountComponentAtNode(container);
  } else if (typeof ReactDOM.unmountComponentAtNode === "function") {
    ReactDOM.unmountComponentAtNode(container);
  }
};

export default unmountApp;

