const tls = require('node:tls');
const { Duplex } = require('node:stream');

function createTlsStreamPair(options = {}) {
  const encrypted = new Duplex({
    write(chunk, enc, cb) {
      cleartext._handle.write(chunk, enc, cb);
    },
    read() {}
  });

  const cleartext = tls.connect({
    ...options,
    socket: encrypted,
    rejectUnauthorized: options.rejectUnauthorized ?? true
  });

  cleartext.on('data', chunk => encrypted.push(chunk));
  cleartext.on('end', () => encrypted.push(null));
  cleartext.on('error', err => encrypted.destroy(err));
  encrypted.on('finish', () => cleartext.end());
  encrypted.on('error', err => cleartext.destroy(err));

  return { encrypted, cleartext };
}

