function parseCertSubject(subject) {
  if (typeof subject !== 'string') return {};

  const s = subject.startsWith('/') ? subject.slice(1) : subject;
  if (!s) return {};

  const parts = [];
  let buf = '';
  let escaped = false;

  for (const ch of s) {
    if (escaped) {
      buf += ch;
      escaped = false;
    } else if (ch === '\\') {
      escaped = true;
    } else if (ch === '/') {
      parts.push(buf);
      buf = '';
    } else {
      buf += ch;
    }
  }
  parts.push(buf);

  return Object.fromEntries(
    parts
      .filter(Boolean)
      .map(part => {
        const i = part.indexOf('=');
        const key = (i === -1 ? part : part.slice(0, i)).trim();
        const value = (i === -1 ? '' : part.slice(i + 1))
          .replace(/\\(.)/g, '$1')
          .trim();
        return [key, value];
      })
      .filter(([key]) => key)
  );
}

