const evaluateExpression = (expression) => {
  if (typeof expression !== 'string') {
    throw new TypeError('Expression must be a string');
  }

  const input = expression.replace(/\s+/g, '');
  if (!/^[\d+\-*/().]+$/.test(input)) {
    throw new Error('Invalid characters in expression');
  }

  let index = 0;

  const parseExpression = () => {
    let value = parseTerm();
    while (index < input.length && /[+-]/.test(input[index])) {
      const op = input[index++];
      const right = parseTerm();
      value = op === '+' ? value + right : value - right;
    }
    return value;
  };

  const parseTerm = () => {
    let value = parseFactor();
    while (index < input.length && /[*/]/.test(input[index])) {
      const op = input[index++];
      const right = parseFactor();
      value = op === '*' ? value * right : value / right;
    }
    return value;
  };

  const parseFactor = () => {
    if (input[index] === '+' || input[index] === '-') {
      const op = input[index++];
      const value = parseFactor();
      return op === '-' ? -value : value;
    }
    if (input[index] === '(') {
      index++;
      const value = parseExpression();
      if (input[index++] !== ')') throw new Error('Mismatched parentheses');
      return value;
    }
    const match = input.slice(index).match(/^\d+(?:\.\d+)?|\.\d+/);
    if (!match) throw new Error('Invalid expression');
    index += match[0].length;
    return Number(match[0]);
  };

  const result = parseExpression();
  if (index !== input.length || !Number.isFinite(result)) {
    throw new Error('Invalid expression');
  }
  return result;
};

