  const keyPath = path.join(__dirname, 'key.pem');

  // Check if cert files exist, if not create self-signed ones
  if (!fs.existsSync(certPath) || !fs.existsSync(keyPath)) {
    const { execSync } = await import('child_process');
    execSync(`openssl req -x509 -newkey rsa:2048 -keyout ${keyPath} -out ${certPath} -days 365 -nodes -subj "/CN=localhost"`, {
      stdio: 'ignore'
    });
  }

  const cert = fs.readFileSync(certPath);
  const key = fs.readFileSync(keyPath);

  // Create TLS server options
  const serverOptions = { cert, key };

  // Create a pair of connected sockets
  const { createConnection } = await import('net');

  return new Promise((resolve) => {
    const server = tls.createServer(serverOptions, (cleartextStream) => {
      // cleartextStream is the decrypted channel
      resolve({
        cleartextStream,
        encryptedStream: null // Will be set when client connects
      });
    });

    server.listen(0, 'localhost', () => {
      const { port } = server.address();

      // Create client connection
      const socket = createConnection({ port, host: 'localhost' }, () => {
        const encryptedStream = tls.connect({
          socket,
          rejectUnauthorized: false
        }, () => {
          // Connection established
          resolve({
            cleartextStream: encryptedStream,
            encryptedStream: socket,
            server
          });
        });
      });
    });
  });
}

