    isServer: true,
    secureContext: createSecureContext(options.server ?? {}),
    ...options,
  });

  const client = new tls.TLSSocket(null, {
    isServer: false,
    secureContext: createSecureContext(options.client ?? {}),
    ...options,
  });

  server.pipe(client);
  client.pipe(server);

  return { server, client };
