    return <div>Current derived value: {this.state.derivedValue}</div>;
  }
}

class ParentComponent extends React.Component {
  state = { value: "initial" };

  componentDidMount() {
    setTimeout(() => this.setState({ value: "updated" }), 2000);
  }

  render() {
    return <ChildComponent value={this.state.value} />;
  }
}

export default ParentComponent;
