import React from "react";

class ScrollTracker extends React.Component {
  constructor(props) {
    super(props);
    this.state = { scrollY: 0 };
    this.prevScrollY = null;
  }

  getSnapshotBeforeUpdate(_prevProps, _prevState) {
    this.prevScrollY = window.scrollY;
    return this.prevScrollY;
  }

  componentDidUpdate(_prevProps, _prevState, snapshot) {
    this.setState({ scrollY: snapshot });
  }

  render() {
    return (
      <div>
        <p>Scroll position before last update: {this.state.scrollY}px</p>
      </div>
    );
  }
}

export default ScrollTracker;
