const evaluateExpression = (expression) => {
  const sanitized = expression.replace(/\s+/g, "");

  if (!/^[\d+\-*/().]+$/.test(sanitized)) {
    throw new Error("Invalid characters in expression");
  }

  const parseExpression = (tokens, pos = { index: 0 }) => {
    let left = parseTerm(tokens, pos);
    while (pos.index < tokens.length && (tokens[pos.index] === "+" || tokens[pos.index] === "-")) {
      const op = tokens[pos.index++];
      const right = parseTerm(tokens, pos);
      left = op === "+" ? left + right : left - right;
    }
    return left;
  };

  const parseTerm = (tokens, pos) => {
    let left = parseFactor(tokens, pos);
    while (pos.index < tokens.length && (tokens[pos.index] === "*" || tokens[pos.index] === "/")) {
      const op = tokens[pos.index++];
      const right = parseFactor(tokens, pos);
      if (op === "/" && right === 0) throw new Error("Division by zero");
      left = op === "*" ? left * right : left / right;
    }
    return left;
  };

  const parseFactor = (tokens, pos) => {
    if (tokens[pos.index] === "(") {
      pos.index++;
      const result = parseExpression(tokens, pos);
      if (tokens[pos.index] !== ")") throw new Error("Mismatched parentheses");
      pos.index++;
      return result;
    }
    const numMatch = tokens.slice(pos.index).join("").match(/^-?\d+(\.\d+)?/);
    if (!numMatch) throw new Error("Unexpected token");
    const num = parseFloat(numMatch[0]);
    pos.index += numMatch[0].length;
    return num;
  };

  const tokens = sanitized.split("");
  const result = parseExpression(tokens, { index: 0 });
  return result;
};

console.log(evaluateExpression("3 + 5 * (2 - 8) / 2"));
